import{_ as i,o as a,c as t,ag as l}from"./chunks/framework.ByAj6Cie.js";const p=JSON.parse('{"title":"Purdue Model","description":"","frontmatter":{},"headers":[],"relativePath":"es/digitalization/purdue-model.md","filePath":"es/digitalization/purdue-model.md"}'),s={name:"es/digitalization/purdue-model.md"};function r(o,e,n,c,d,u){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="purdue-model" tabindex="-1">Purdue Model <a class="header-anchor" href="#purdue-model" aria-label="Permalink to &quot;Purdue Model&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Purdue Model is a reference architecture used to structure industrial systems into hierarchical levels.</p><p>It defines how systems are organized from physical processes up to enterprise systems. This structure helps manage communication, security, and system responsibilities.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of the Purdue Model is to:</p><ul><li>Provide a clear structure for industrial system design</li><li>Separate functions based on their role and criticality</li><li>Control data flow between different system levels</li><li>Support secure integration between OT and IT systems</li></ul><p>It helps engineers design systems that are easier to manage and protect.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>The Purdue Model divides industrial systems into levels, each with a specific function.</p><h3 id="level-0-–-physical-process" tabindex="-1">Level 0 – Physical Process <a class="header-anchor" href="#level-0-–-physical-process" aria-label="Permalink to &quot;Level 0 – Physical Process&quot;">​</a></h3><ul><li>Sensors and actuators</li><li>Direct interaction with the physical process</li></ul><h3 id="level-1-–-basic-control" tabindex="-1">Level 1 – Basic Control <a class="header-anchor" href="#level-1-–-basic-control" aria-label="Permalink to &quot;Level 1 – Basic Control&quot;">​</a></h3><ul><li>PLCs and local controllers</li><li>Real time control of equipment</li></ul><h3 id="level-2-–-supervisory-control" tabindex="-1">Level 2 – Supervisory Control <a class="header-anchor" href="#level-2-–-supervisory-control" aria-label="Permalink to &quot;Level 2 – Supervisory Control&quot;">​</a></h3><ul><li>HMI and SCADA systems</li><li>Monitoring and operator interaction</li></ul><h3 id="level-3-–-operations-management" tabindex="-1">Level 3 – Operations Management <a class="header-anchor" href="#level-3-–-operations-management" aria-label="Permalink to &quot;Level 3 – Operations Management&quot;">​</a></h3><ul><li>Production management systems</li><li>Data aggregation and coordination of operations</li></ul><h3 id="level-4-–-enterprise-systems" tabindex="-1">Level 4 – Enterprise Systems <a class="header-anchor" href="#level-4-–-enterprise-systems" aria-label="Permalink to &quot;Level 4 – Enterprise Systems&quot;">​</a></h3><ul><li>Business systems such as ERP</li><li>Planning, analytics, and business processes</li></ul><p>Communication typically flows between adjacent levels. Direct communication across multiple levels is limited to reduce complexity and risk.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>The Purdue Model is used in:</p><ul><li>Design of industrial network architectures</li><li>Integration between control systems and enterprise systems</li><li>Cybersecurity planning and segmentation</li><li>Standardization of system structure across facilities</li></ul><p>It is widely applied in manufacturing, energy, and infrastructure systems.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li>Not all systems strictly follow every level</li><li>Modern architectures may combine or bypass levels</li><li>Direct connections between distant levels increase risk</li><li>The model is a guideline, not a strict requirement</li><li>Integration with modern technologies must be carefully managed</li></ul><p>The model should be adapted to the specific needs of each system.</p><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Use the model as a starting point for structuring systems</li><li>Clearly define which devices belong to each level</li><li>Control communication between levels using defined rules</li><li>Avoid unnecessary connections between control and enterprise layers</li><li>Keep documentation aligned with the defined architecture</li></ul><p>The Purdue Model provides a clear framework for organizing industrial systems and managing their interactions.</p>',31)])])}const m=i(s,[["render",r]]);export{p as __pageData,m as default};
